void setup() {
  size(800, 800);
  background(10);
  noFill();
  stroke(255, 80);
  strokeWeight(0.6);
}

void draw() {
  float cx = width/2;
  float cy = height/2;

  for (int i = 0; i < 120; i++) {
    float r = map(i, 0, 120, 20, 340);
    float dev = noise(i * 0.04,
      frameCount * 0.008) * 60;
    float angle = TWO_PI * i / 120;
    float x = cx + cos(angle) * (r + dev);
    float y = cy + sin(angle) * (r + dev);
    if (i == 0) {
      beginShape();
      curveVertex(x, y);
    } else {
      curveVertex(x, y);
    }
    if (i == 119) endShape(CLOSE);
  }

  if (frameCount > 200) noLoop();
}
